function toggleTips(){let e=document.getElementById("tipsText");"none"===e.style.display?e.style.display="block":e.style.display="none"}function showTime(){let e=(new Date).toLocaleTimeString(),t=document.getElementById("time");t&&(t.innerHTML="Current Time: "+e)}function scrollToTop(){window.scrollTo({top:0,behavior:"smooth"})}setInterval(showTime,1e3),document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll("img").forEach(e=>{e.addEventListener("click",function(){this.style.border="3px solid red"})})});